  ('judicial-57f41407-moex-00163', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲未經許可於河床採取砂石，同時違反水利法而應科處罰鍰，並構成刑法上的竊佔罪。下列敘述何者正確？', '["依從新從輕原則，應課處行政罰鍰", "應先依據刑法追究責任，如獲不起訴處分，再依水利法之規定處罰", "此屬一行為違反數規定，處罰之種類不同，可同時處罰", "此屬一行為違反數個行政法義務，應以法定最重之處罰裁處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00164', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於買賣契約性質之敘述，何者正確？', '["要物契約", "雙務契約", "單務契約", "要式契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00165', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列何種情況，國家不負損害賠償責任？', '["非公務員之人受委託行使公權力，因過失致人民之自由或權利受侵害", "民間團體受委託管理公共設施，因設置有欠缺致人民之身體受損害者", "被害人為外國人，依條約或其本國法令或慣例，中華民國人得在該國與該國人享受同等權利", "管理機關已於開放之水域等為適當之警告或標示，而人民仍得從事具危險性活動者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00166', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列何者非屬行政罰？', '["罰鍰", "沒入", "停止營業", "斷絕營業所必須之自來水、電力或其他能源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00167', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '行政機關對於人民依法申請之案件，於法定期限內應作為而不作為時，申請人應如何提起行政救濟？', '["由於無行政處分之存在，申請人可直接向行政法院提起課予義務之訴", "行政機關消極不作為，亦應先經訴願程序尋求救濟", "向上級機關提出陳情", "向民事法院提起國家賠償訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00168', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '檢察官甲拘提被告乙後，於在途解送時訊問乙，所取得乙之自白及其他不利之陳述，其證據能力應如何判斷？', '["原則上不得作為證據", "其證據能力之有無，事實審法院得任意判斷", "其證據能力之有無，應依自由心證原則判斷", "一律有證據能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00169', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲向高雄市政府Ａ戶政事務所申請更名為原住民姓名遭拒。若甲不服欲提起救濟，應向何者提起訴願？', '["高雄市政府Ａ戶政事務所", "高雄市政府民政局", "高雄市政府", "內政部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00170', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '有關訴願審議之方式，下列敘述何者正確？', '["一律須經言詞辯論，始得作成決定", "僅訴願人得陳述意見，原處分機關不得表示意見", "鑑定所需費用一律由訴願人負擔", "受理訴願機關應依訴願人之申請，調查證據。但就申請調查之證據，認為不必要者，亦得不調查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00171', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依民事通常程序，下列何者非屬得於第二審提出新攻擊或防禦方法之事由？', '["因第一審法院違背法令致未能提出", "事實為法院職務上所已知", "對於第一審已提出之防禦方法為補充", "事實發生於第一審法院言詞辯論終結前，且可歸責於當事人之事由，致未能於第一審提出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00172', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於民事訴訟法上當事人能力之有無，下列敘述何者錯誤？', '["法人經解散並清算完結者，無當事人能力", "自然人經宣告為受監護宣告之人者，無當事人能力", "非法人之團體，雖無法人格，如設有代表人或管理人，仍有當事人能力", "中央或地方機關，雖無獨立之人格，仍有當事人能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
